export const firstPagePresentingObligation = (root, obligationId) => {
  if (root.kind === 'page') {
    const entries = [...(root.presents ?? []), ...(root.presentsForEach ?? [])]
    return entries.some((entry) => entry.obligation === obligationId)
      ? root
      : null
  }
  for (const child of root.sections ?? root.children ?? []) {
    const found = firstPagePresentingObligation(child, obligationId)
    if (found) return found
  }
  return null
}

export const firstUnfulfilledPage = (root, evaluation, options = {}) => {
  if (root.kind) {
    const status = containerStatus(root, evaluation, options)
    if (status === NOT_APPLICABLE || status === FULFILLED) {
      return null
    }
    if (root.kind === PAGE) {
      return root
    }
  }
  for (const child of root.sections ?? root.children ?? []) {
    const found = firstUnfulfilledPage(child, evaluation, options)
    if (found) {
      return found
    }
  }
  return null
}

